    private fun processSharedImage(uri: Uri) {
        Log.d(TAG, "Processing image: $uri")

        try {
            val mimeType = contentResolver.getType(uri)
            val cursor = contentResolver.query(uri, null, null, null, null)
            var fileSize: Long = -1

            cursor?.use {
